// 三载体一致：裁剪 JSON 树映射到 docx 原生类，再打包 Blob
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType } from 'https://cdn.jsdelivr.net/npm/docx@9/+esm';
const sections=data.document.sections.map(s=>({properties:s.properties??{},children:s.children.map(p=>new Paragraph({heading:p.heading?HeadingLevel[p.heading]:undefined,alignment:p.alignment?AlignmentType[p.alignment]:undefined,spacing:p.spacing,children:p.runs.map(r=>new TextRun(r))}))}));
const document = new Document({sections});
const blob = await Packer.toBlob(document);
